import{_ as s,c as a,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Fonctionnalités de la Plateforme : Commandes Essentielles et Gestion des Skills | OpenSkills","description":"Apprenez les fonctionnalités de la plateforme OpenSkills, maîtrisez les opérations essentielles comme les commandes, l'installation, la liste, la mise à jour et la suppression des skills, et comprenez les différences entre la gestion globale et par projet.","frontmatter":{"title":"Fonctionnalités de la Plateforme : Commandes Essentielles et Gestion des Skills | OpenSkills","sidebarTitle":"Maîtriser les Opérations Essentielles","subtitle":"Fonctionnalités de la Plateforme : Commandes Essentielles et Gestion des Skills | OpenSkills","description":"Apprenez les fonctionnalités de la plateforme OpenSkills, maîtrisez les opérations essentielles comme les commandes, l'installation, la liste, la mise à jour et la suppression des skills, et comprenez les différences entre la gestion globale et par projet.","order":2},"headers":[],"relativePath":"fr/numman-ali/openskills/platforms/index.md","filePath":"fr/numman-ali/openskills/platforms/index.md"}`),i={name:"fr/numman-ali/openskills/platforms/index.md"};function r(o,e,n,d,c,p){return l(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="fonctionnalites-de-la-plateforme" tabindex="-1">Fonctionnalités de la Plateforme <a class="header-anchor" href="#fonctionnalites-de-la-plateforme" aria-label="Permalink to &quot;Fonctionnalités de la Plateforme&quot;">​</a></h1><p>Ce chapitre explore en profondeur les commandes essentielles de l&#39;OpenSkills CLI et les fonctionnalités de gestion des skills, vous aidant à passer de &quot;savoir utiliser&quot; à &quot;maîtriser&quot;.</p><h2 id="prerequis" tabindex="-1">Prérequis <a class="header-anchor" href="#prerequis" aria-label="Permalink to &quot;Prérequis&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Veuillez vérifier avant de commencer</p><p>Avant d&#39;étudier ce chapitre, assurez-vous d&#39;avoir terminé le chapitre <a href="./../start/">Démarrage Rapide</a>, en particulier :</p><ul><li><a href="./../start/installation/">Installation d&#39;OpenSkills</a> : OpenSkills CLI installé avec succès</li><li><a href="./../start/first-skill/">Installation de votre Premier Skill</a> : Comprendre le processus d&#39;installation de base des skills</li></ul></div><h2 id="contenu-de-ce-chapitre" tabindex="-1">Contenu de ce Chapitre <a class="header-anchor" href="#contenu-de-ce-chapitre" aria-label="Permalink to &quot;Contenu de ce Chapitre&quot;">​</a></h2><p>Ce chapitre comprend 6 thèmes couvrant toutes les fonctionnalités essentielles d&#39;OpenSkills :</p><h3 id="detail-des-commandes" tabindex="-1"><a href="./cli-commands/">Détail des Commandes</a> <a class="header-anchor" href="#detail-des-commandes" aria-label="Permalink to &quot;[Détail des Commandes](./cli-commands/)&quot;">​</a></h3><p>Présentation complète des 7 commandes, des paramètres et des options, avec un tableau de référence rapide des commandes. Idéal pour les utilisateurs qui ont besoin de rechercher rapidement l&#39;utilisation des commandes.</p><h3 id="sources-d-installation-en-detail" tabindex="-1"><a href="./install-sources/">Sources d&#39;Installation en Détail</a> <a class="header-anchor" href="#sources-d-installation-en-detail" aria-label="Permalink to &quot;[Sources d&#39;Installation en Détail](./install-sources/)&quot;">​</a></h3><p>Explication détaillée des trois sources d&#39;installation : dépôts GitHub, chemins locaux et dépôts Git privés. Les scénarios d&#39;utilisation, le format des commandes et les points d&#39;attention pour chaque méthode.</p><h3 id="installation-globale-vs-installation-locale-par-projet" tabindex="-1"><a href="./global-vs-project/">Installation Globale vs Installation Locale par Projet</a> <a class="header-anchor" href="#installation-globale-vs-installation-locale-par-projet" aria-label="Permalink to &quot;[Installation Globale vs Installation Locale par Projet](./global-vs-project/)&quot;">​</a></h3><p>Explication des différences entre l&#39;installation <code>--global</code> et l&#39;installation par défaut (locale par projet), vous aidant à choisir l&#39;emplacement d&#39;installation approprié et à comprendre les règles de priorité de recherche des skills.</p><h3 id="lister-les-skills-installes" tabindex="-1"><a href="./list-skills/">Lister les Skills Installés</a> <a class="header-anchor" href="#lister-les-skills-installes" aria-label="Permalink to &quot;[Lister les Skills Installés](./list-skills/)&quot;">​</a></h3><p>Apprenez à utiliser la commande <code>list</code> pour voir les skills installés et comprendre la signification des étiquettes de position <code>(project)</code> et <code>(global)</code>.</p><h3 id="mettre-a-jour-les-skills" tabindex="-1"><a href="./update-skills/">Mettre à Jour les Skills</a> <a class="header-anchor" href="#mettre-a-jour-les-skills" aria-label="Permalink to &quot;[Mettre à Jour les Skills](./update-skills/)&quot;">​</a></h3><p>Guidez-vous pour utiliser la commande <code>update</code> pour actualiser les skills installés, prenant en charge la mise à jour complète et la mise à jour de skills spécifiques, en maintenant la synchronisation des skills avec le dépôt source.</p><h3 id="supprimer-les-skills" tabindex="-1"><a href="./remove-skills/">Supprimer les Skills</a> <a class="header-anchor" href="#supprimer-les-skills" aria-label="Permalink to &quot;[Supprimer les Skills](./remove-skills/)&quot;">​</a></h3><p>Présentation de deux méthodes de suppression : la commande <code>manage</code> interactive et la commande <code>remove</code> scriptée, vous aidant à gérer efficacement votre bibliothèque de skills.</p><h2 id="parcours-d-apprentissage" tabindex="-1">Parcours d&#39;Apprentissage <a class="header-anchor" href="#parcours-d-apprentissage" aria-label="Permalink to &quot;Parcours d&#39;Apprentissage&quot;">​</a></h2><p>Selon vos besoins, choisissez le parcours d&#39;apprentissage approprié :</p><h3 id="parcours-a-apprentissage-systematique-recommande-pour-les-debutants" tabindex="-1">Parcours A : Apprentissage Systématique (Recommandé pour les Débutants) <a class="header-anchor" href="#parcours-a-apprentissage-systematique-recommande-pour-les-debutants" aria-label="Permalink to &quot;Parcours A : Apprentissage Systématique (Recommandé pour les Débutants)&quot;">​</a></h3><p>Suivez tous les contenus dans l&#39;ordre pour établir un système de connaissances complet :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Détail des Commandes → Sources d&#39;Installation → Global vs Projet → Lister les Skills → Mettre à Jour les Skills → Supprimer les Skills</span></span></code></pre></div><h3 id="parcours-b-consultation-a-la-demande" tabindex="-1">Parcours B : Consultation à la Demande <a class="header-anchor" href="#parcours-b-consultation-a-la-demande" aria-label="Permalink to &quot;Parcours B : Consultation à la Demande&quot;">​</a></h3><p>Accédez directement selon votre tâche actuelle :</p><table tabindex="0"><thead><tr><th>Que voulez-vous faire ?</th><th>Lire cet article</th></tr></thead><tbody><tr><td>Trouver l&#39;utilisation d&#39;une commande</td><td><a href="./cli-commands/">Détail des Commandes</a></td></tr><tr><td>Installer un skill depuis un dépôt privé</td><td><a href="./install-sources/">Sources d&#39;Installation en Détail</a></td></tr><tr><td>Décider d&#39;installer en global ou en projet</td><td><a href="./global-vs-project/">Global vs Projet</a></td></tr><tr><td>Voir quels skills sont installés</td><td><a href="./list-skills/">Lister les Skills Installés</a></td></tr><tr><td>Mettre à jour les skills vers la dernière version</td><td><a href="./update-skills/">Mettre à Jour les Skills</a></td></tr><tr><td>Nettoyer les skills inutilisés</td><td><a href="./remove-skills/">Supprimer les Skills</a></td></tr></tbody></table><h2 id="prochaines-etapes" tabindex="-1">Prochaines Étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines Étapes&quot;">​</a></h2><p>Après avoir terminé ce chapitre, vous maîtriserez les skills d&#39;utilisation quotidienne d&#39;OpenSkills. Ensuite, vous pouvez :</p><ul><li><strong><a href="./../advanced/">Fonctionnalités Avancées</a></strong> : Apprendre le mode Universal, les chemins de sortie personnalisés, les liens symboliques, la création de skills personnalisés et d&#39;autres fonctionnalités avancées</li><li><strong><a href="./../faq/">FAQ</a></strong> : Consulter la FAQ et le guide de dépannage en cas de problème</li></ul>',29)])])}const h=s(i,[["render",r]]);export{m as __pageData,h as default};
